#!/usr/bin/env node
// harbor-tools — small command-line utilities for local workflows.
// Keep the core commands minimal and easy to understand.

const fs = require('fs');
const path = require('path');

const USAGE = `Usage: bench-cli <command> [options]

Commands:
  hello [--name NAME]        Print a greeting (default name: "world")
  version                    Print the CLI version from package.json
  --help, -h                 Show this help

Examples:
  bench-cli hello
  bench-cli hello --name alice
  bench-cli version
`;

function readPackageVersion() {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const raw = fs.readFileSync(pkgPath, 'utf8');
  return JSON.parse(raw).version;
}

function parseNameFlag(argv) {
  const idx = argv.indexOf('--name');
  if (idx === -1) return 'world';
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--name requires a value');
    process.exit(1);
  }
  return value;
}

function failCart(error) {
  process.stderr.write(`${JSON.stringify(error)}\n`);
  process.exit(2);
}

function runCart(argv) {
  const inputIndex = argv.indexOf('--input');
  const inputPath = argv[inputIndex + 1];
  if (inputIndex === -1 || !inputPath || inputPath.startsWith('-')) {
    failCart({ error: 'invalid_input' });
  }

  let input;
  try {
    input = fs.readFileSync(inputPath, 'utf8');
  } catch {
    failCart({ error: 'invalid_input' });
  }

  let cart;
  try {
    cart = JSON.parse(input);
  } catch {
    failCart({ error: 'invalid_json' });
  }

  if (!cart || !Array.isArray(cart.items) || cart.items.length === 0) {
    failCart({ error: 'missing_items' });
  }

  const catalogPath = path.join(__dirname, '..', 'data', 'catalog.json');
  const catalog = JSON.parse(fs.readFileSync(catalogPath, 'utf8'));
  const quantities = new Map();

  for (const item of cart.items) {
    if (!item || typeof item !== 'object' || !Object.prototype.hasOwnProperty.call(catalog.products, item.sku)) {
      failCart({ error: 'invalid_sku', sku: item && item.sku });
    }
    if (typeof item.qty !== 'number' || !Number.isInteger(item.qty) || item.qty <= 0) {
      failCart({ error: 'invalid_quantity', sku: item.sku });
    }
    quantities.set(item.sku, (quantities.get(item.sku) || 0) + item.qty);
  }

  if (cart.coupon !== null && !Object.prototype.hasOwnProperty.call(catalog.coupons, cart.coupon)) {
    failCart({ error: 'invalid_coupon' });
  }
  if (!Object.prototype.hasOwnProperty.call(catalog.tax_rates, cart.state)) {
    failCart({ error: 'invalid_state' });
  }

  for (const [sku, qty] of quantities) {
    const product = catalog.products[sku];
    if (qty > product.stock) {
      failCart({ error: 'invalid_stock', sku, available: product.stock, requested: qty });
    }
  }

  let subtotalCents = 0;
  let lineDiscountCents = 0;
  let taxablePostLineDiscountCents = 0;
  const items = [];

  for (const [sku, qty] of quantities) {
    const product = catalog.products[sku];
    const promotion = catalog.line_promotions.find((entry) => entry.sku === sku);
    const lineSubtotalCents = product.unit_cents * qty;
    let discount = 0;

    if (promotion && promotion.type === 'buy_x_get_y_free') {
      discount = Math.floor(qty / (promotion.buy_qty + promotion.free_qty)) * promotion.free_qty * product.unit_cents;
    }
    if (promotion && promotion.type === 'per_unit_discount_cents' && qty >= promotion.min_qty) {
      discount = promotion.per_unit_discount_cents * qty;
    }

    const lineTotalCents = lineSubtotalCents - discount;
    subtotalCents += lineSubtotalCents;
    lineDiscountCents += discount;
    if (catalog.taxable_codes[product.tax_code] === true) {
      taxablePostLineDiscountCents += lineTotalCents;
    }
    items.push({
      sku,
      qty,
      line_subtotal_cents: lineSubtotalCents,
      line_discount_cents: discount,
      line_total_cents: lineTotalCents,
    });
  }

  const taxCents = Math.round(taxablePostLineDiscountCents * catalog.tax_rates[cart.state]);
  const postLineDiscountCents = subtotalCents - lineDiscountCents;
  const couponDiscountCents = cart.coupon !== null && postLineDiscountCents >= catalog.coupons[cart.coupon].min_subtotal_cents
    ? Math.round(postLineDiscountCents * catalog.coupons[cart.coupon].percent / 100)
    : 0;
  const shippingCents = postLineDiscountCents - couponDiscountCents >= catalog.free_shipping_min_cents
    ? 0
    : catalog.shipping_cents;
  const totalCents = postLineDiscountCents - couponDiscountCents + taxCents + shippingCents;

  console.log(JSON.stringify({
    subtotal_cents: subtotalCents,
    line_discount_cents: lineDiscountCents,
    coupon_discount_cents: couponDiscountCents,
    tax_cents: taxCents,
    shipping_cents: shippingCents,
    total_cents: totalCents,
    items,
  }));
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      console.log(readPackageVersion());
      return;
    }
    case 'cart': {
      runCart(rest);
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

