const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function writeCart(t, cart) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'harbor-tools-cart-'));
  const inputPath = path.join(directory, 'cart.json');
  fs.writeFileSync(inputPath, JSON.stringify(cart));
  t.after(() => fs.rmSync(directory, { recursive: true, force: true }));
  return inputPath;
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('cart combines duplicate SKUs and applies pricing rules', (t) => {
  const inputPath = writeCart(t, {
    state: 'CA',
    coupon: 'ORDER10',
    items: [
      { sku: 'TEE', qty: 2 },
      { sku: 'TEE', qty: 1 },
      { sku: 'BAG', qty: 2 },
      { sku: 'MUG', qty: 1 },
    ],
  });

  assert.deepStrictEqual(JSON.parse(run(['cart', '--input', inputPath])), {
    subtotal_cents: 15100,
    line_discount_cents: 3500,
    coupon_discount_cents: 1160,
    tax_cents: 858,
    shipping_cents: 0,
    total_cents: 11298,
    items: [
      { sku: 'TEE', qty: 3, line_subtotal_cents: 7500, line_discount_cents: 2500, line_total_cents: 5000 },
      { sku: 'BAG', qty: 2, line_subtotal_cents: 6400, line_discount_cents: 1000, line_total_cents: 5400 },
      { sku: 'MUG', qty: 1, line_subtotal_cents: 1200, line_discount_cents: 0, line_total_cents: 1200 },
    ],
  });
});

test('cart reports combined stock validation errors on stderr', (t) => {
  const inputPath = writeCart(t, {
    state: 'CA',
    coupon: null,
    items: [{ sku: 'BAG', qty: 3 }, { sku: 'BAG', qty: 2 }],
  });
  let failure;

  try {
    run(['cart', '--input', inputPath]);
  } catch (error) {
    failure = error;
  }

  assert.ok(failure);
  assert.strictEqual(failure.status, 2);
  assert.strictEqual(failure.stdout, '');
  assert.deepStrictEqual(JSON.parse(failure.stderr), {
    error: 'invalid_stock',
    sku: 'BAG',
    available: 4,
    requested: 5,
  });
});

